              if (n.decorators?.length) label += `\n@${n.decorators.join('\n@')}`;
              if (n.docstring) label += `\n\n${n.docstring.slice(0, 150)}${n.docstring.length > 150 ? '...' : ''}`;
              return label;
            }}
            linkCurvature={graphMode === 'curvy' ? 0.25 : 0}
            linkColor={getLinkColor}
