                ? Math.max(14 / globalScale, (node.val || 1) * 2)
                : radius * 1.5;
              ctx.fillStyle = color;
              ctx.beginPath();
              ctx.arc(node.x, node.y, hitSize, 0, 2 * Math.PI, false);
